import { React, useState } from 'react'
import { Container, Grid, Paper, TextField, makeStyles, Button, IconButton, Tooltip, Card, CardContent, MenuItem, Box } from '@material-ui/core'
import StudentActivities from '../components/StudentActivities'
import { AttachFileRounded } from '@material-ui/icons'
import { useLocation, useParams } from 'react-router-dom'
import axios from 'axios'
import { useEffect } from 'react'

import Cookies from 'js-cookie'

const useStyle = makeStyles(theme => {
  return {
    paper: {
      padding: theme.spacing(2)
    },
    input: {
      display: 'none'
    }
  }
})

export default function StudentFeed({}) {

  const classes = useStyle()
  // const location = useLocation()
  // const subject = location.search.slice(1)
  // const subjectSpace = subject.replace("%20", " ")
  const Cookie = Cookies.get('studentID');



let  {id}  = useParams();
const [subjectInfo, setSubjectInfo] = useState({});

function getClassrooms() {
  const sendData = {
    updateID: id
  };


  axios.post('http://localhost:80/api/getClassroomID.php', sendData)
  .then(response => {
      if(response.data == 0) {
        console.log('classroom ID not found');
      } else {
        setSubjectInfo(response.data[0]);
      }
  })
}



function streamFeed() {
  
  axios.post('https://ursacapi.000webhostapp.com/api/getPost.php', id)
      .then((response) => {
        if (response.data == 0) {
          setNoPost(true);
      } else {
          setActivities(response.data)
          setNoPost(false);
      }

      })
      .catch(error => {
          console.log(error);
      })
}

  useEffect(() => {
    streamFeed();
    getClassrooms();
  }, []);

  const [noPost, setNoPost] = useState(true);
  const [postData, setPostData] = useState('');


  const [activities, setActivities] = useState([])

  const handlePost = (e) => {
    e.preventDefault();
    const sendData = {
      postData,
      id
    };

    axios.post('https://ursacapi.000webhostapp.com/api/addPost.php', sendData)
    .then(response => {
      console.log(response.data);
    })
    .catch(err => console.log(err))
  }

  
  return (
    <div className={classes.root}>
      <Container maxWidth='sm'>
        <Grid container spacing={3} >

          <Grid item xs={12}>
            <h1>{subjectInfo.subjectName}</h1>
            <p>{subjectInfo.yearSection}</p>
          </Grid>

          <Grid item xs={12}>
            <Paper className={classes.paper} >

              <div>
                <form onSubmit={handlePost} >
                  <TextField
                    variant='filled'
                    type='text'
                    name='body'
                    value={postData}
                    onChange={(e) => {setPostData(e.target.value);}}
                    color='secondary'
                    label='Announcement'
                    minRows={4}
                    margin='normal'
                    fullWidth
                    multiline
                  />

                  <input className={classes.input} onChange={(e) => console.log(e.target.value)} type="file" accept='image/*' id='attach-file' />
                  <label htmlFor="attach-file">
                    <IconButton component='span'><Tooltip title='Attach a file' placement='right-start' ><AttachFileRounded /></Tooltip></IconButton>
                  </label>

                    <Button variant='contained' color='secondary' type='submit' size='large' fullWidth disableElevation>Post</Button>

                </form>

              </div>
            </Paper>
          </Grid>
          {
            noPost ?

              <Paper variant='outlined' >
                <MenuItem disabled>
                  You have no announcement yet.
                </MenuItem>
              </Paper>

              :

              <Box>
                {activities.map(activity => (
                  <Grid item xs={12} key={activity.id}>
                    <StudentActivities activity={activity} />
                  </Grid>
                ))}
              </Box>

          }


        </Grid>
      </Container>
    </div>
  )
}
